/**
 * canvas-init.js — the AI Canvas page.
 *
 * The canvas HTML is generated by the ErnosPlain engine on the source machine and
 * fetched here, then dropped into a sandboxed iframe via srcdoc. Because srcdoc is
 * same-origin (allow-same-origin, but NO allow-scripts — nothing the model emits can
 * run), the page can hook every <form> the model produces: on submit we intercept,
 * show an "inferring" spinner, POST the form state back for the next screen, and swap
 * it in. So EVERY interaction — the first prompt and every button after — shows that
 * the local model is thinking. Kept external so the SPA re-runs it on navigation.
 */
(function () {
  var BASE = window.CANVAS_BASE || window.location.origin;
  function q(id) { return document.getElementById(id); }

  function init() {
    var frame = q("canvas-frame");
    if (!frame) return;
    var overlay = q("canvas-loading");
    var stat = q("canvas-status");
    var off = q("canvas-offline");
    var busy = false;

    function setStatus(cls, html) { if (stat) { stat.className = "cm-status " + cls; stat.innerHTML = html; } }
    function showOverlay(on) { if (overlay) overlay.style.display = on ? "flex" : "none"; }

    // Each srcdoc swap fires load — hide the spinner and re-hook the new screen's forms.
    frame.addEventListener("load", function () {
      showOverlay(false);
      busy = false;
      try {
        var doc = frame.contentDocument;
        if (!doc) return;
        var forms = doc.querySelectorAll("form");
        for (var i = 0; i < forms.length; i++) forms[i].addEventListener("submit", onSubmit);
      } catch (e) { /* opaque frame — shouldn't happen with allow-same-origin */ }
    });

    function onSubmit(e) {
      e.preventDefault();
      if (busy) return;
      var params = new URLSearchParams();
      new FormData(e.currentTarget).forEach(function (v, k) { params.append(k, v); });
      // include the clicked button's name/value (native submit would; FormData won't)
      if (e.submitter && e.submitter.name) params.append(e.submitter.name, e.submitter.value || "");
      go("POST", params.toString());
    }

    function go(method, body) {
      busy = true;
      showOverlay(true);
      var opts = { method: method };
      if (method === "POST") {
        opts.body = body;
        opts.headers = { "Content-Type": "application/x-www-form-urlencoded" };
      }
      fetch(BASE + "/htmlgen", opts)
        .then(function (r) { return r.text(); })
        .then(function (html) { frame.srcdoc = html; })  // load handler hides the spinner
        .catch(function () {
          showOverlay(false); busy = false;
          setStatus("is-offline", "🌙 <strong>The host went offline mid-thought.</strong> Try again when it's back.");
        });
    }

    // Boot: only show the canvas if the machine answers.
    fetch(BASE + "/ping").then(function (r) { if (!r.ok) throw 0; }).then(function () {
      frame.style.display = "block";
      if (off) off.style.display = "none";
      setStatus("is-online", "🟢 <strong>Live</strong> — every pixel below is built by a local model and streamed as raw HTML.");
      go("GET", null);
    }).catch(function () {
      frame.style.display = "none";
      showOverlay(false);
      if (off) off.style.display = "block";
      setStatus("is-offline", "🌙 <strong>The host is asleep.</strong> The canvas runs live on Maria's machine — come back when it's online.");
    });
  }

  init();
  window.canvas_page_init = init;
})();
